import{_ as t,o as s,c as a,ag as i}from"./chunks/framework.Dn0B0GT3.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/quick-start.md","filePath":"getting-started/quick-start.md"}'),n={name:"getting-started/quick-start.md"};function r(o,e,l,p,h,d){return s(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>This guide walks you through your first session with ShellPort, from starting the server to connecting to your terminal from a browser.</p><h2 id="step-1-start-the-server" tabindex="-1">Step 1: Start the Server <a class="header-anchor" href="#step-1-start-the-server" aria-label="Permalink to &quot;Step 1: Start the Server&quot;">​</a></h2><p>Run the <code>server</code> command:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span></span></code></pre></div><p>On first launch, you&#39;ll see output similar to:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>🌐 Open in browser: http://localhost:7681/#&lt;random-secret&gt;</span></span></code></pre></div><p>ShellPort will also display a QR code for TOTP 2FA pairing (if this is your first time or TOTP has been reset).</p><h2 id="step-2-open-the-web-terminal" tabindex="-1">Step 2: Open the Web Terminal <a class="header-anchor" href="#step-2-open-the-web-terminal" aria-label="Permalink to &quot;Step 2: Open the Web Terminal&quot;">​</a></h2><ol><li>Open the URL in your browser (the secret is embedded in the URL fragment after <code>#</code>)</li><li>If this is your first session, you&#39;ll be prompted to scan the QR code with your authenticator app (Google Authenticator, Authy, 1Password, etc.)</li><li>Enter the 6-digit code from your authenticator app to complete authentication</li></ol><h2 id="default-security-settings" tabindex="-1">Default Security Settings <a class="header-anchor" href="#default-security-settings" aria-label="Permalink to &quot;Default Security Settings&quot;">​</a></h2><p>ShellPort ships with security enabled by default:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><strong>Encryption</strong></td><td>Enabled</td><td>AES-256-GCM E2E encryption with auto-generated secret</td></tr><tr><td><strong>TOTP 2FA</strong></td><td>Enabled</td><td>Time-based one-time password required on first login</td></tr><tr><td><strong>Approval Mode</strong></td><td>Enabled</td><td>Server host must approve each connection</td></tr></tbody></table><h3 id="understanding-the-url" tabindex="-1">Understanding the URL <a class="header-anchor" href="#understanding-the-url" aria-label="Permalink to &quot;Understanding the URL&quot;">​</a></h3><p>The URL contains your session secret after the <code>#</code> fragment:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>http://localhost:7681/#&lt;random-secret&gt;</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>The secret in the URL fragment is never sent to the server — it stays in your browser. This is by design for E2E encryption.</p></div><h2 id="step-3-approve-the-connection-first-time" tabindex="-1">Step 3: Approve the Connection (First Time) <a class="header-anchor" href="#step-3-approve-the-connection-first-time" aria-label="Permalink to &quot;Step 3: Approve the Connection (First Time)&quot;">​</a></h2><p>When a client connects for the first time, the server displays an approval prompt:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[?] Allow connection from 192.168.1.x? (y/n)</span></span></code></pre></div><p>Type <code>y</code> to approve. The client will then complete the TOTP authentication.</p><h2 id="step-4-use-the-terminal" tabindex="-1">Step 4: Use the Terminal <a class="header-anchor" href="#step-4-use-the-terminal" aria-label="Permalink to &quot;Step 4: Use the Terminal&quot;">​</a></h2><p>Once connected, you&#39;ll see the terminal interface. You can:</p><ul><li>Type commands as normal</li><li>Open new tabs with the <code>+</code> button in the sidebar</li><li>Switch between sessions via the sidebar</li><li>Resize the terminal by dragging the window</li></ul><h2 id="security-modes" tabindex="-1">Security Modes <a class="header-anchor" href="#security-modes" aria-label="Permalink to &quot;Security Modes&quot;">​</a></h2><p>If you want to adjust security settings:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Encrypted only, skip TOTP (trusted network)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-totp</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># TOTP only, no encryption (over VPN/Tailscale)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># No security (localhost only)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">shellport</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-secret</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --no-totp</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>Only disable security features on trusted networks. The defaults (encryption + TOTP + approval) are recommended for production use.</p></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><ul><li>Learn about all available server options</li><li>Explore the NanoTermV2 library for embedding the terminal</li><li>Understand the security architecture</li></ul>`,30)])])}const g=t(n,[["render",r]]);export{u as __pageData,g as default};
